#include <iostream>

int add(int a, int b);
int subtract(int a, int b);

int main() {
    int a, b;
    std::cin >> a >> b;
    std::cout << "Sum: " << add(a, b) << "\n";
    std::cout << "Diff: " << subtract(a, b) << "\n";
    return 0;
}

int add(int a, int b) {
    return a + b;
}

int subtract(int a, int b) {
    return a - b;
}

